-- Enrichment marathon batch: RackTables, Radarr, Radicale, Railway, rallly, Ralph, Ramp, Rancher

-- ── RackTables ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$RackTables is a free, open-source web application for datacenter and server room asset management, tracking rack space, hardware, IP networks, and cabling.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (self-hosted, no paid tiers)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2004, founded_year),
  company_size = COALESCE($q$Open-source community project, no formal company$q$, company_size),
  headquarters = COALESCE($q$N/A (community-maintained open-source project)$q$, headquarters),
  languages = ARRAY[$q$PHP$q$]::text[],
  seo_title = COALESCE($q$RackTables Review 2026: Features, Pricing, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what RackTables offers for datacenter asset management: rack visualization, IPAM, VLAN tracking, pricing (free/open source), and key features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$RackTables is a free, open-source data center infrastructure management (DCIM) and IT asset management web application originally launched in 2004 and released under the GNU General Public License version 2 (GPLv2). It is written in PHP and stores data in a MySQL database, making it self-hostable on any Linux server with a standard LAMP-style stack. RackTables has no owning company; it is maintained by a community of contributors, with Denis Ovsienko listed in copyright notices dating back to 2006, and the canonical source repository hosted on GitHub under the RackTables organization, mirrored at git.racktables.org. The tool is designed to document and visualize the physical and logical layout of server rooms and data centers: it models real-world rack elevations, tracks typed rack-mountable objects (servers, switches, PDUs, patch panels) with flexible, user-defined attribute sets, and supports a tagging system for flexible categorization beyond simple hierarchies. Its IP address management (IPAM) module tracks IPv4 and IPv6 networks, is NAT-aware, and can model virtual routers and load balancers, which is unusual for a free tool in this category. RackTables also handles VLAN management, structured cabling and patch-panel documentation, and 802.1Q trunk tracking. A universal search function lets administrators locate any object, rack, IP address, or attribute value quickly, and a multi-user access model with permission controls allows teams to collaborate without a single shared login. The software can integrate with network monitoring tools such as Cacti and Munin, and it supports neighbor discovery via CDP and LLDP to help reconcile documented topology against what is actually connected. Because it has no vendor, RackTables carries no licensing fees, subscription costs, or usage limits; the tradeoff is that support is community-based (mailing lists, wiki, and GitHub issues) rather than a commercial SLA. It does not run natively on Windows, requiring a Linux (or other Unix-like) host, and it lacks the modern SaaS conveniences of newer DCIM tools (guided onboarding, hosted multi-tenant SaaS, built-in floor-plan drag-and-drop editors), instead favoring a form-driven, database-first workflow. Despite its age, RackTables remains a common recommendation for small and mid-sized organizations, universities, hosting providers, and internal IT teams that want a lightweight, dependency-light, zero-cost system of record for rack space, hardware inventory, and IP address allocation without committing to a commercial DCIM platform such as Device42, Netbox Cloud, or Sunbird. It continues to see active releases, with version 0.22.0 as its latest stable line and a live public demo available for evaluation before deployment.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4a6cf529-e980-41a6-a8bd-f9fddd93fce3';

