-- ── Radarr ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Radarr is a free, open-source movie collection manager that automatically monitors, downloads, sorts, and upgrades movies via Usenet and BitTorrent.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (self-hosted, donation-funded)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$Volunteer open-source community, no formal company$q$, company_size),
  headquarters = COALESCE($q$N/A (open-source community project)$q$, headquarters),
  languages = ARRAY[$q$C#$q$, $q$.NET$q$, $q$JavaScript$q$, $q$React$q$]::text[],
  seo_title = COALESCE($q$Radarr Review 2026: Features, Setup, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Explore Radarr, the free open-source movie manager that automates downloading, sorting, and quality upgrades. Features, pricing, and FAQs inside.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Radarr is a free, open-source movie collection manager built for Usenet and BitTorrent users, released under the GNU General Public License v3 (GPLv3). It began around 2016 as a community fork of Sonarr, the TV-show equivalent PVR, reworked to handle movies in a style inspired by the earlier CouchPotato project; by January 2017 it was circulating publicly in alpha form and has since grown into one of the most widely deployed tools in the self-hosted media automation space, commonly referred to as part of the 'Servarr' or '*arr' suite alongside Sonarr (TV), Lidarr (music), Readarr (books), and Prowlarr (indexer management). Radarr has no company behind it; it is maintained entirely by volunteer contributors and funded through community donations via Open Collective, with source code hosted on GitHub under the Radarr organization. Functionally, Radarr acts as the central brain of an automated movie library: users define root folders and quality profiles, and Radarr continuously monitors configured indexers and RSS feeds for matching releases, sending the first qualifying result to a connected download client such as SABnzbd, NZBGet, qBittorrent, Deluge, Transmission, or rTorrent. Once a download completes, Radarr automatically imports, renames, and organizes the file into the library using customizable naming conventions, and it fetches supporting metadata including posters, cast information, plot descriptions, and ratings. A standout feature is automatic quality upgrading: Radarr can keep watching for better versions of movies already in the library (for example, replacing a DVD rip with a Blu-ray release) according to a quality profile's allowed resolutions and cutoff. Custom formats extend this further, letting users score releases by codec, HDR metadata, release group, streaming source, or arbitrary regex patterns so that the preferred version is consistently selected over lesser alternatives. Radarr integrates natively with media servers such as Plex, Kodi, and Emby for library refreshes and notifications, offers a calendar view of upcoming releases, and supports numerous notification channels including Discord, Telegram, email, and Pushover. It runs cross-platform on Windows, Linux, macOS, and Raspberry Pi, and is commonly deployed via Docker on home servers and NAS devices such as Synology and Unraid. Because Radarr is entirely self-hosted and free, there are no subscription tiers, seat limits, or paid feature gates; its only costs are the hosting infrastructure, storage, and any indexer or download-client subscriptions a user chooses to pair it with. Support is community-driven through the Servarr wiki, Discord, Reddit, and GitHub issues rather than a commercial help desk. Radarr's open architecture, active development, and tight integration with the broader *arr ecosystem have made it a de facto standard for anyone building a self-managed movie library, distinguishing it from closed, cloud-hosted streaming or media-management products by giving users complete control over their own content and infrastructure.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'faf3dbd9-cf17-44f0-87da-3ad94eaa9671';

