-- ── Radicale ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Radicale is a lightweight, open-source CalDAV and CardDAV server for self-hosting calendars, to-do lists, and contacts with minimal setup.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (self-hosted)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$Small open-source maintainer team (Kozea)$q$, company_size),
  headquarters = COALESCE($q$Lyon, France (Kozea)$q$, headquarters),
  languages = ARRAY[$q$Python$q$]::text[],
  seo_title = COALESCE($q$Radicale Review 2026: Features, Setup, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what Radicale offers for self-hosted calendars and contacts: CalDAV/CardDAV support, features, pricing (free/open source), and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Radicale is a free, open-source CalDAV (calendar) and CardDAV (contacts) server created by French developer Guillaume Ayoub, with initial code committed to its source repository at the very end of 2008. It is maintained under the Kozea organization, a small France-based collective of open-source Python developers based in Lyon who also maintain related projects like WeasyPrint and CairoSVG. Radicale is released under the GNU General Public License version 3 (GPLv3) and written entirely in Python, running on Linux, BSD, macOS, and Windows. Its defining design philosophy is simplicity: rather than attempting to implement the entire CalDAV and CardDAV specifications exhaustively, Radicale focuses on working out of the box with minimal configuration, storing all data directly on the file system in a straightforward folder structure that is easy to back up, inspect, or migrate without a database server. Radicale shares calendars and contact lists over CalDAV, CardDAV, and plain HTTP, supporting events, to-dos, journal entries, and business cards (vCard contacts), and it is compatible with a wide range of client applications, including Thunderbird (via the CalDAV-Sync or built-in support), Apple Calendar and Contacts, DAVx5 on Android, GNOME Evolution, and many mobile calendar apps. Authentication is flexible and pluggable, supporting mechanisms such as htpasswd files, PAM, LDAP, and custom authentication backends, and access can be further restricted through a configurable rights/authorization system. Radicale can secure connections directly with TLS, avoiding the need for a reverse proxy in simple deployments, though many production installs still front it with nginx or Apache for additional hardening and performance. The project can be extended with plugins for authentication, storage backends, and web interfaces. Because it has no commercial parent company, Radicale carries no license fees or subscription costs; anyone can download, self-host, and modify it freely. Development is active, with the latest stable release (3.7.6) shipping in mid-2026 and the project maintaining roughly 4,800 GitHub stars, 500+ forks, and adoption by more than 170 dependent projects, according to its GitHub repository statistics. Notably, the maintainers report that some users run Radicale in demanding production environments, including managing medical scheduling calendars handling thousands of requests per day, demonstrating that despite its lightweight footprint, the server is robust enough for real operational workloads. Radicale is commonly chosen by privacy-conscious individuals, small businesses, and self-hosting communities (frequently featured in 'awesome-selfhosted' style lists) as a drop-in replacement for proprietary calendar and contacts sync services like Google Calendar or iCloud, particularly when paired with tools like Nextcloud, home lab reverse proxies, or standalone VPS deployments where users want full control over their scheduling and contact data without relying on a third-party cloud provider.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '95330f45-8ddc-4fe4-b00d-c7498b26f5ac';

