-- ── rallly ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Rallly is an open-source group scheduling tool that lets organizers create polls of available times so participants can vote on the best meeting date.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (free hobby tier plus paid Pro subscription)$q$, pricing_model),
  starting_price = COALESCE($q$Free (Pro plan at $56 per year)$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Small, independent open-source project led by a single core maintainer$q$, company_size),
  headquarters = COALESCE($q$N/A (independent open-source project)$q$, headquarters),
  languages = ARRAY[$q$TypeScript$q$, $q$JavaScript$q$]::text[],
  seo_title = COALESCE($q$Rallly Review 2026: Features, Pricing, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Rallly's open-source scheduling polls work, pricing (free plus $56/yr Pro), self-hosting options, features, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Rallly is a free, open-source group scheduling and collaboration tool built by developer Luke Vella and released under the GNU Affero General Public License v3 (AGPLv3), designed as an alternative to commercial tools like Doodle, Calendly, and When2Meet. The core workflow is simple: an organizer creates a poll listing several candidate dates and available times for a meeting or event, shares a link with participants, and those participants vote on which options work for them, with no account or login required to respond to a poll. Rallly is available both as a hosted web application at rallly.co and as a self-hostable open-source project distributed as a Docker image, allowing individuals, teams, and organizations to run their own instance for full data control; a single-user self-hosted deployment is free, while multi-user self-hosted deployments require a paid license, and the source code and translation contribution guides are maintained publicly on GitHub. The hosted product uses a freemium model: the Hobby tier is free forever and lets users create and answer polls without logging in, but inactive polls (those with all date options in the past and no activity for 30 or more days) are automatically deleted; the Pro tier costs $56 per year (marketed with an early-adopter promotion equivalent to roughly four months free) and adds the ability to keep polls indefinitely, access to all platform features, early access to new functionality, and a locked-in subscription rate that is protected from future price increases. Rallly has attracted a large user base for an independently maintained open-source tool, with over 188,000 registered users and more than 300,000 polls created according to the project's own reported statistics, and it maintains a highly rated public reputation among self-hosting and productivity communities. The interface is localized into multiple languages through community-contributed translations coordinated via Crowdin, making it accessible to a global audience of executive assistants, administrative professionals, and event organizers who need a lightweight way to coordinate group availability without lengthy email threads. Unlike venture-backed scheduling competitors, Rallly operates on a lean, user-funded model, relying on Pro subscriptions and community goodwill rather than outside investment, and it positions itself specifically around simplicity, minimal setup, and respect for privacy through its self-hosting option. Because it is open source, technically inclined users can audit the code, contribute features or translations, or fork the project entirely, while non-technical users can simply use the hosted rallly.co service with the same polling workflow.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '03916389-8c72-4b6c-ac5d-c652f169146c';

