-- ── Ramp ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Ramp is a corporate card and spend management platform that combines charge cards, expense management, bill pay, and AI-driven finance automation.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (free core plan plus paid per-user tiers)$q$, pricing_model),
  starting_price = COALESCE($q$Free (Plus plan at $15 per user per month)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Large scale-up, employee count not publicly disclosed; over $1 billion in annualized revenue$q$, company_size),
  headquarters = COALESCE($q$New York City, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Ramp Review 2026: Pricing, Features, Funding, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Ramp's corporate card and spend management platform works: pricing plans, features, 2026 funding at a $44B valuation, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Ramp is a financial technology company that provides corporate charge cards, expense management, bill payment, and AI-driven spend automation software for businesses. Ramp was founded in March 2019 by Eric Glyman, Karim Atiyeh, and Gene Lee, and formally launched to customers in February 2020, with Glyman serving as CEO and Atiyeh as CTO; the company is headquartered in New York City, with additional offices in Miami and San Francisco. Ramp has grown rapidly since launch, and in June 2026 it announced a $750 million Series F funding round at a $44 billion valuation, led by ICONIQ, GIC (Singapore's sovereign wealth fund), and Ontario Teachers' Pension Plan, with additional participation from Goldman Sachs Alternatives, D.E. Shaw and Co., Morgan Stanley Investment Management, Generation Investment Management, Insight Partners, and BroadLight Capital; the round brought Ramp's total equity financing raised to more than $3 billion. CEO Eric Glyman has stated the company crossed $1 billion in annualized revenue with positive free cash flow, and Ramp reported total payment volume growth of roughly 170 percent year over year as of March 2026, a rate the company describes as its fastest in three years despite its much larger size. Ramp's core product suite centers on the corporate card, which issues unlimited physical and virtual cards with granular, card-level spend controls, paired with automated expense management, receipt collection via OCR, and real-time accounting sync to platforms including QuickBooks Online, Xero, NetSuite, and Sage Intacct. Beyond the card, Ramp offers bill pay with no fees on wires or transfers, FDIC-insured treasury and banking-like accounts, procurement workflows, travel booking, and a growing suite of AI features, including AI-assisted expense coding, automated approval recommendations, and AI-powered custom financial reporting, which the company has increasingly emphasized as a growth driver amid broader enterprise AI spending. Pricing follows a three-tier structure: the free Standard plan includes unlimited cards, 1.5 percent cash back, basic policy controls, and core accounting integrations at no monthly cost; the Plus plan costs $15 per user per month (with an approximate 20 percent discount for annual billing) and adds multi-entity management, custom procurement approvals, HRIS integrations, and multi-currency bill payments; and the Enterprise plan offers custom pricing with dedicated account management, 24/7 priority support, custom API integrations, and SOC 2 Type II compliance reporting for large, complex organizations. Ramp positions itself against both traditional corporate card issuers like American Express and newer fintech competitors like Brex, differentiating primarily through its free entry tier, cash-back incentives, and heavy investment in AI-driven automation of finance operations, which it argues reduces the manual work traditionally required from finance and accounting teams.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '73bfc873-4265-4959-93b9-df520ad9fcd5';

